import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const Tracking = () => {
  const [activeTab, setActiveTab] = useState('onprogress');
  const [trucks, setTrucks] = useState([]);
  const [selectedDate, setSelectedDate] = useState('');

  useEffect(() => {
    const url = `http://localhost:5000/api/trucks?status=${activeTab}${selectedDate ? `&date=${selectedDate}` : ''}`;
    fetch(url)
      .then((res) => res.json())
      .then((data) => setTrucks(data))
      .catch((err) => console.error("Failed to fetch trucks:", err));
  }, [activeTab, selectedDate]);

  return (
    <div className="flex min-h-screen bg-gradient-to-br from-gray-100 to-blue-100">
      {/* Sidebar */}
      <div className="bg-gradient-to-br from-indigo-900 to-purple-700 text-white w-64 p-6 flex flex-col justify-between shadow-lg">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="https://via.placeholder.com/50" alt="Admin Icon" className="rounded-full mb-2 shadow" />
            <h2 className="font-bold text-xl">Admin</h2>
          </div>
          <div className="space-y-4">
            <Link to="/master-data" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center transition duration-200">Master Data</Link>
            <Link to="/tracking" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center transition duration-200">Tracking</Link>
            <Link to="/info-driver" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center transition duration-200">Info Driver</Link>
          </div>
        </div>
        <div className="space-y-4 mt-6">
          <Link to="/settings" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center transition duration-200">Settings</Link>
          <Link to="/logout" className="block bg-red-600 hover:bg-red-500 rounded-lg p-3 text-center transition duration-200">Logout</Link>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8 bg-white rounded-tl-3xl shadow-inner">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-3xl font-bold text-gray-800">Dashboard</h1>
          <div className="flex items-center space-x-3">
            <button
              onClick={() => setActiveTab('onprogress')}
              className={`px-4 py-2 rounded-full font-medium transition duration-200 ${
                activeTab === 'onprogress' ? 'bg-blue-600 text-white shadow-md' : 'bg-white border border-blue-600 text-blue-600'
              }`}
            >
              On Progress
            </button>
            <button
              onClick={() => setActiveTab('finished')}
              className={`px-4 py-2 rounded-full font-medium transition duration-200 ${
                activeTab === 'finished' ? 'bg-green-600 text-white shadow-md' : 'bg-white border border-green-600 text-green-600'
              }`}
            >
              Finished
            </button>
            <button
              onClick={() => setActiveTab('trouble')}
              className={`px-4 py-2 rounded-full font-medium transition duration-200 ${
                activeTab === 'trouble' ? 'bg-red-600 text-white shadow-md' : 'bg-white border border-red-600 text-red-600'
              }`}
            >
              Trouble
            </button>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="border border-gray-300 p-2 rounded-lg shadow-sm"
            />
          </div>
        </div>

        {/* Truck Cards */}
        <div className="grid grid-cols-1 gap-6">
          {trucks.length === 0 ? (
            <p className="text-center text-gray-600">Tidak ada truk dengan status "<strong>{activeTab}</strong>"</p>
          ) : (
            trucks.map((truck) => (
              <div key={truck.id} className="bg-gradient-to-tr from-white via-gray-50 to-blue-50 p-4 rounded-xl shadow-md transition-transform hover:scale-105">
                <div className="flex items-center space-x-6">
                  <img
                    src={truck.image || "https://via.placeholder.com/150"}
                    alt="Truck"
                    className="w-32 h-32 object-cover rounded-lg border border-gray-300"
                  />
                  <div>
                    <h3 className="text-xl font-semibold text-indigo-700 mb-1">Truck ID: {truck.id}</h3>
                    <p className="text-sm text-gray-700">Truck Type: <strong>{truck.type === 'fuso' ? 'Truck Fuso' : 'Dump Truck'}</strong></p>
                    <p className="text-sm text-gray-700">Driver: {truck.driver}</p>
                    <p className="text-sm text-gray-700">Status: <span className="italic capitalize">{truck.status}</span></p>
                    <p className="text-sm text-gray-700">Date: {truck.timestamp?.split('T')[0]}</p>
                    <div className="mt-4">
                      <img
                        src="https://via.placeholder.com/300x200?text=Peta+Lokasi"
                        alt="Map"
                        className="rounded-lg border"
                      />
                    </div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Tracking;
